INSERT INTO `customer_metric_definitions` (`id`, `section_name`, `section_sort`, `metric_key`, `label`, `definition`, `metric_sort`, `is_active`) VALUES
(1, 'Identity & Overview', 1, 'first_name', 'First Name', 'The first name of the customer as recorded during their first transaction.', 1, 1),
(2, 'Identity & Overview', 1, 'gender', 'Gender', 'The gender of the customer as detected from their name.', 2, 1),
(3, 'Identity & Overview', 1, 'msisdn', 'Phone Number', 'The mobile number used by the customer for all recorded transactions.', 3, 1),
(4, 'Identity & Overview', 1, 'first_transaction', 'First Transaction', 'The date and time of the first ever payment recorded from this customer.', 4, 1),
(5, 'Identity & Overview', 1, 'last_transaction', 'Last Transaction', 'The date and time of the most recent payment recorded from this customer.', 5, 1),
(6, 'Identity & Overview', 1, 'customer_age_days', 'Customer Age (Days)', 'The number of days since the customer first made a payment at this business.', 6, 1),
(7, 'Identity & Overview', 1, 'customer_age_months', 'Customer Age (Months)', 'The number of months since the customer first made a payment.', 7, 1),
(8, 'Identity & Overview', 1, 'days_since_last', 'Days Since Last Visit', 'The number of days that have passed since the customer last made a payment.', 8, 1),
(9, 'Spending Statistics', 2, 'all_time_spend', 'All Time Spend', 'The total amount of money spent by the customer across all recorded transactions.', 1, 1),
(10, 'Spending Statistics', 2, 'average_spend', 'Average Spend', 'The average transaction value. It is calculated as: Total Spend divided by Total Transactions.', 2, 1),
(11, 'Spending Statistics', 2, 'highest_transaction', 'Highest Transaction', 'The largest single payment ever made by the customer.', 3, 1),
(12, 'Spending Statistics', 2, 'lowest_transaction', 'Lowest Transaction', 'The smallest payment recorded from the customer.', 4, 1),
(13, 'Spending Statistics', 2, 'all_time_transactions', 'Total Transactions', 'The total number of payments made by the customer.', 5, 1),
(14, 'Visit Behavior', 3, 'average_return_interval_days', 'Average Return Interval', 'The average number of days between each customer visit.', 1, 1),
(15, 'Visit Behavior', 3, 'longest_interval_days', 'Longest Visit Gap', 'The longest period of inactivity between two visits.', 2, 1),
(16, 'Visit Behavior', 3, 'visit_frequency_per_month', 'Visits Per Month', 'The average number of visits the customer makes each month.', 3, 1),
(17, 'Visit Behavior', 3, 'spend_velocity_per_month', 'Spend Velocity Per Month', 'The average monthly revenue generated by the customer.', 4, 1),
(18, 'Revenue Contribution', 4, 'revenue_share_percent', 'Revenue Share', 'The percentage of total business revenue that comes from this customer.', 1, 1),
(19, 'Customer Ranking', 5, 'customer_rank', 'Customer Rank', 'The ranking position of the customer when all customers are ordered by total spending. Rank 1 represents the highest spending customer.', 1, 1),
(20, 'Customer Ranking', 5, 'top_spender_percentile', 'Top Spender Percentile', 'The percentile ranking of the customer among all customers based on spending.', 2, 1),
(21, 'Customer Ranking', 5, 'spending_segment', 'Spending Segment', 'Customers are grouped into segments based on their spending percentile. Whale (top 1%), VIP (top 5%), High Value (top 10%), Regular (top 50%), Low Value (remaining).', 3, 1),
(22, 'Customer Loyalty & Lifecycle', 6, 'loyalty_tier', 'Loyalty Tier', 'A loyalty classification used to group customers by value and engagement. Tiers: Bronze, Silver, Gold, Platinum, Diamond.', 1, 1),
(23, 'Customer Loyalty & Lifecycle', 6, 'lifecycle_stage', 'Lifecycle Stage', 'The stage of the customer relationship based on visit count.', 2, 1),
(24, 'Churn Prediction', 7, 'churn_risk', 'Churn Risk', 'A classification indicating the likelihood that the customer may stop visiting the business.', 1, 1),
