  `cashier_user_id` int(11) DEFAULT NULL COMMENT 'User who processed checkout',
  `payment_method_id` int(10) UNSIGNED NOT NULL COMMENT 'FK ÔåÆ payment_methods',
  `mpesa_config_id` int(10) UNSIGNED DEFAULT NULL COMMENT 'FK ÔåÆ mpesa_configs if mpesa',
  `pesapal_config_id` int(10) UNSIGNED DEFAULT NULL COMMENT 'FK ÔåÆ pesapal_configs if pesapal',
  `amount` decimal(12,2) NOT NULL,
  `gross_amount` decimal(12,2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT 'Full price before discount. Equals amount when no discount applied.',
  `discount_amount` decimal(12,2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT 'Discount deducted. net (amount) = gross_amount - discount_amount.',
  `discount_reason` varchar(200) DEFAULT NULL COMMENT 'Required when discount_amount > 0. Auditable justification.',
  `discount_by_user_id` int(10) UNSIGNED DEFAULT NULL COMMENT 'User who applied the discount (cashier or manager).',
  `description` varchar(255) DEFAULT NULL COMMENT 'Bill number / table / note',
  `mode` enum('manual','api') NOT NULL DEFAULT 'manual' COMMENT 'manual = staff confirms; api = programmatic (STK push etc.)',
  `api_checkout_request_id` varchar(255) DEFAULT NULL,
  `api_merchant_request_id` varchar(255) DEFAULT NULL,
  `api_receipt` varchar(255) DEFAULT NULL,
  `api_raw_response` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Raw API response stored for audit' CHECK (json_valid(`api_raw_response`)),
  `mpesa_payment_id` int(11) DEFAULT NULL COMMENT 'FK ÔåÆ mpesa_payments.id ÔÇö set when callback arrives',
  `msisdn` varchar(20) DEFAULT NULL COMMENT 'Captured phone ÔÇö nullable (customer may skip)',
  `customer_id` bigint(20) UNSIGNED DEFAULT NULL COMMENT 'FK ÔåÆ customers ÔÇö set when msisdn is captured',
  `loyalty_account_id` int(11) DEFAULT NULL,
  `loyalty_points_awarded` decimal(12,2) NOT NULL DEFAULT 0.00,
  `loyalty_auto_awarded` tinyint(1) NOT NULL DEFAULT 0,
  `loyalty_auto_awarded_amount` decimal(12,2) NOT NULL DEFAULT 0.00,
  `loyalty_awarded_at` datetime DEFAULT NULL,
  `loyalty_award_source` varchar(50) DEFAULT NULL,
  `loyalty_points_redeemed` int(11) NOT NULL DEFAULT 0 COMMENT 'Points redeemed as payment',
  `status` enum('pending','processing','complete','failed','cancelled') NOT NULL DEFAULT 'pending',
  `completed_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Canonical POS transaction record. One row per checkout completion attempt.';

